// SPDX-License-Identifier: MIT
pragma solidity ^0.8.35;

import "./Errors.sol";

library Validation {
    uint8 internal constant LEVEL_COUNT = 17;

    function validateLevel(uint8 level) internal pure {
        if (level < 1 || level > LEVEL_COUNT) {
            revert InvalidLevel(level);
        }
    }

    function isPrizeCell(uint256 cellId) internal pure returns (bool) {
        return cellId >= 7 && ((cellId + 1) & cellId) == 0;
    }

    function depthOf(uint256 cellId) internal pure returns (uint256 depth) {
        while (cellId > 1) {
            cellId = cellId / 2;
            depth++;
        }
    }
}

contracts/EasyGameAdvance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.35;

import "./base/Types.sol";
import "./base/Errors.sol";
import "./base/Validation.sol";
import "./base/Storage.sol";

contract EasyGameAdvance is EasyGameAdvanceStorage {

    event LevelActivated(
        address indexed player,
        uint8 indexed level,
        uint256 value,
        uint256 cellId
    );
    event PaymentSplit(
        address indexed player,
        uint8 indexed level,
        uint256 matrixPrizeAmount,
        uint256 directReferralAmount,
        uint256 secondLineAmount,
        uint256 thirdLineAmount,
        uint256 projectFeeAmount
    );
    event TokenPaymentSplit(
        address indexed player,
        uint8 indexed level,
        address indexed token,
        uint256 matrixPrizeAmount,
        uint256 directReferralAmount,
        uint256 secondLineAmount,
        uint256 thirdLineAmount,
        uint256 projectFeeAmount
    );
    event ProjectFeeAccrued(
        uint8 indexed level,
        uint256 amount,
        uint256 totalAccrued
    );
    event ProjectFeesWithdrawn(address indexed wallet, uint256 amount);
    event TokenProjectFeeAccrued(
        address indexed token,
        uint8 indexed level,
        uint256 amount,
        uint256 totalAccrued
    );
    event TokenProjectFeesWithdrawn(address indexed token, address indexed wallet, uint256 amount);
    event MatrixPlaced(
        address indexed player,
        uint8 indexed level,
        uint256 indexed cellId,
        uint256 parentCellId
    );
    event ReferralBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event SecondLineBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event ThirdLineBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event WeightUpdated(
        address indexed player,
        uint8 indexed level,
        uint256 totalWeight
    );
    event Recycled(
        address indexed player,
        uint8 indexed level,
        uint256 recycleCount,
        uint256 newCellId
    );
    event BoxTokenGranted(
        address indexed player,
        uint8 indexed level,
        uint256 amount
    );
    event PrizePositionReached(
        address indexed player,
        uint8 indexed level,
        uint256 indexed cellId,
        uint256 amount,
        bool pending
    );
    event TokenPrizePositionReached(
        address indexed player,
        uint8 indexed level,
        address indexed token,
        uint256 cellId,
        uint256 amount,
        bool pending
    );
    event DrawRequested(
        uint8 indexed level,
        uint256 randomSeed,
        uint256 totalWeight
    );
    event DrawWon(
        address indexed winner,
        uint8 indexed level,
        uint256 amount,
        bool pending
    );
    event TokenDrawWon(
        address indexed winner,
        uint8 indexed level,
        address indexed token,
        uint256 amount,
        bool pending
    );
    event ReferralBonusClaimed(address indexed player, uint256 amount);
    event PrizeClaimed(address indexed player, uint8 indexed level, uint256 amount);
    event TokenReferralBonusClaimed(address indexed player, address indexed token, uint256 amount);
    event TokenPrizeClaimed(address indexed player, address indexed token, uint8 indexed level, uint256 amount);
    event LevelFrozen(address indexed player, uint8 indexed level);
    event LevelUnfrozen(address indexed player, uint8 indexed level);
    event LevelPriceChanged(uint8 indexed level, uint256 oldPrice, uint256 newPrice);
    event LevelUsdcPriceChanged(uint8 indexed level, uint256 oldPrice, uint256 newPrice);
    event LevelAvailabilityChanged(uint8 indexed level, bool available);
    event WalletsChanged(address projectWallet, address treasuryWallet, address operatorWallet);
    event UsdcTokenChanged(address indexed oldToken, address indexed newToken);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier nonReentrant() {
        require(_reentrancyLock == 1, "Reentrant call");
        _reentrancyLock = 2;
        _;
        _reentrancyLock = 1;
    }

    constructor(
        address projectWallet_,
        address treasuryWallet_,
        address operatorWallet_,
        address usdcToken_
    ) {
        if (projectWallet_ == address(0)) revert ZeroAddress();
        if (treasuryWallet_ == address(0)) revert ZeroAddress();
        if (operatorWallet_ == address(0)) revert ZeroAddress();
        if (usdcToken_ == address(0)) revert ZeroAddress();

        owner = msg.sender;
        projectWallet = projectWallet_;
        treasuryWallet = treasuryWallet_;
        operatorWallet = operatorWallet_;
        usdcToken = IERC20Minimal(usdcToken_);

        levelPrices[1] = 0.05 ether;
        levelPrices[2] = 0.07 ether;
        levelPrices[3] = 0.1 ether;
        levelPrices[4] = 0.14 ether;
        levelPrices[5] = 0.2 ether;
        levelPrices[6] = 0.28 ether;
        levelPrices[7] = 0.4 ether;
        levelPrices[8] = 0.55 ether;
        levelPrices[9] = 0.8 ether;
        levelPrices[10] = 1.1 ether;
        levelPrices[11] = 1.6 ether;
        levelPrices[12] = 2.2 ether;
        levelPrices[13] = 3.2 ether;
        levelPrices[14] = 4.4 ether;
        levelPrices[15] = 6.5 ether;
        levelPrices[16] = 8 ether;
        levelPrices[17] = 12 ether;

        levelPricesUsdc[1] = 50000;
        levelPricesUsdc[2] = 70000;
        levelPricesUsdc[3] = 100000;
        levelPricesUsdc[4] = 140000;
        levelPricesUsdc[5] = 200000;
        levelPricesUsdc[6] = 280000;
        levelPricesUsdc[7] = 400000;
        levelPricesUsdc[8] = 550000;
        levelPricesUsdc[9] = 800000;
        levelPricesUsdc[10] = 1100000;
        levelPricesUsdc[11] = 1600000;
        levelPricesUsdc[12] = 2200000;
        levelPricesUsdc[13] = 3200000;
        levelPricesUsdc[14] = 4400000;
        levelPricesUsdc[15] = 6500000;
        levelPricesUsdc[16] = 8000000;
        levelPricesUsdc[17] = 12000000;

        for (uint8 level = 3; level <= LEVEL_COUNT; level++) {
            levelAvailable[level] = true;
        }
    }

    receive() external payable {
        revert("Use activateLevel");
    }

    function activateLevel(uint8 level, address inviter) external payable nonReentrant {
        _validateLevel(level);
        require(levelAvailable[level], "Level is not available yet");
        require(msg.value == levelPrices[level], "Incorrect payment amount");

        uint256 cellId = _activateLevelState(level, msg.sender, inviter);
        _splitPayment(level, msg.sender, msg.value);

        emit LevelActivated(msg.sender, level, msg.value, cellId);
    }

    function activateLevelWithUSDC(uint8 level, address inviter) external nonReentrant {
        _validateLevel(level);
        require(levelAvailable[level], "Level is not available yet");
        require(address(usdcToken) != address(0), "USDC token not configured");

        uint256 amount = levelPricesUsdc[level];
        require(amount > 0, "USDC price is not configured");
        require(
            usdcToken.transferFrom(msg.sender, address(this), amount),
            "USDC transfer failed"
        );

        uint256 cellId = _activateLevelState(level, msg.sender, inviter);
        _splitUsdcPayment(level, msg.sender, amount);

        emit LevelActivated(msg.sender, level, amount, cellId);
    }

    function _activateLevelState(uint8 level, address playerAddress, address inviter)
        private
        returns (uint256 cellId)
    {
        Player storage player = players[playerAddress];
        PlayerLevel storage state = playerLevels[playerAddress][level];
        require(!state.active, "Level is already active");

        _registerPlayer(player, playerAddress, inviter);

        state.active = true;
        state.frozen = false;
        state.tickets += 1;
        player.totalTickets += 1;
        player.lastActiveAt = block.timestamp;

        cellId = _placePlayer(level, playerAddress);
        _addWeight(playerAddress, level, BASE_ACTIVATION_WEIGHT, 0);
        _unfreezeLowerLevels(playerAddress, level);
    }

    function claimReferralBonus() external nonReentrant {
        uint256 amount = players[msg.sender].claimableReferralBonus;
        require(amount > 0, "No referral bonus");

        players[msg.sender].claimableReferralBonus = 0;
        _safeTransfer(payable(msg.sender), amount);

        emit ReferralBonusClaimed(msg.sender, amount);
    }

    function claimReferralBonusUSDC() external nonReentrant {
        uint256 amount = claimableReferralBonusUsdc[msg.sender];
        require(amount > 0, "No USDC referral bonus");
        require(address(usdcToken) != address(0), "USDC token not configured");

        claimableReferralBonusUsdc[msg.sender] = 0;
        _safeTransferToken(usdcToken, msg.sender, amount);

        emit TokenReferralBonusClaimed(msg.sender, address(usdcToken), amount);
    }

    function claimPrize(uint8 level) external nonReentrant {
        _validateLevel(level);
        PlayerLevel storage state = playerLevels[msg.sender][level];
        require(!state.frozen, "Level is frozen");

        uint256 amount = state.claimablePrize;
        require(amount > 0, "No prize");

        state.claimablePrize = 0;
        players[msg.sender].claimablePrize -= amount;
        _safeTransfer(payable(msg.sender), amount);

        emit PrizeClaimed(msg.sender, level, amount);
    }

    function claimPrizeUSDC(uint8 level) external nonReentrant {
        _validateLevel(level);
        require(address(usdcToken) != address(0), "USDC token not configured");
        PlayerLevel storage state = playerLevels[msg.sender][level];
        require(!state.frozen, "Level is frozen");

        uint256 amount = claimablePrizeUsdcByLevel[msg.sender][level];
        require(amount > 0, "No USDC prize");

        claimablePrizeUsdcByLevel[msg.sender][level] = 0;
        claimablePrizeUsdc[msg.sender] -= amount;
        _safeTransferToken(usdcToken, msg.sender, amount);

        emit TokenPrizeClaimed(msg.sender, address(usdcToken), level, amount);
    }

    function withdrawProjectFees() external onlyOwner nonReentrant {
        uint256 amount = projectFeesAccrued;
        require(amount > 0, "No project fees");

        projectFeesAccrued = 0;
        _safeTransfer(payable(projectWallet), amount);

        emit ProjectFeesWithdrawn(projectWallet, amount);
    }

    function withdrawProjectFeesUSDC() external onlyOwner nonReentrant {
        require(address(usdcToken) != address(0), "USDC token not configured");
        uint256 amount = projectFeesAccruedUsdc;
        require(amount > 0, "No USDC project fees");

        projectFeesAccruedUsdc = 0;
        _safeTransferToken(usdcToken, projectWallet, amount);

        emit TokenProjectFeesWithdrawn(address(usdcToken), projectWallet, amount);
    }

    function requestDraw(uint8 level) external onlyOwner nonReentrant {
        _validateLevel(level);

        uint256 totalWeight = totalWeightByLevel[level];
        require(totalWeight > 0, "No weight");

        uint256 reward = (matrixPrizePools[level] * DRAW_REWARD_BPS) / BPS;
        uint256 usdcReward = (matrixPrizePoolsUsdc[level] * DRAW_REWARD_BPS) / BPS;
        require(reward > 0 || usdcReward > 0, "No draw reward");

        uint256 randomSeed = uint256(
            keccak256(
                abi.encodePacked(
                    block.prevrandao,
                    block.timestamp,
                    block.number,
                    level,
                    totalWeight,
                    matrixPrizePools[level]
                )
            )
        );
        uint256 winningPoint = (randomSeed % totalWeight) + 1;
        address winner = _weightedWinner(level, winningPoint);
        require(winner != address(0), "Winner not found");

        if (reward > 0) {
            matrixPrizePools[level] -= reward;
            _creditPrize(winner, level, reward);
        }
        if (usdcReward > 0) {
            matrixPrizePoolsUsdc[level] -= usdcReward;
            _creditPrizeUsdc(winner, level, usdcReward);
        }

        emit DrawRequested(level, randomSeed, totalWeight);
        emit DrawWon(winner, level, reward, playerLevels[winner][level].frozen);
        if (usdcReward > 0) {
            emit TokenDrawWon(
                winner,
                level,
                address(usdcToken),
                usdcReward,
                playerLevels[winner][level].frozen
            );
        }
    }

    function getPlayer(address playerAddress) external view returns (Player memory) {
        return players[playerAddress];
    }

    function getPlayerLevel(address playerAddress, uint8 level)
        external
        view
        returns (
            bool active,
            bool frozen,
            uint256 cycles,
            uint256 positionId,
            uint256 earned
        )
    {
        _validateLevel(level);
        PlayerLevel storage state = playerLevels[playerAddress][level];
        return (
            state.active,
            state.frozen,
            state.cycleCount,
            state.cellId,
            state.claimablePrize + state.pendingPrize
        );
    }

    function getPlayerLevelFull(address playerAddress, uint8 level)
        external
        view
        returns (PlayerLevel memory)
    {
        _validateLevel(level);
        return playerLevels[playerAddress][level];
    }

    function getPlayerWeight(address playerAddress, uint8 level)
        external
        view
        returns (uint256)
    {
        _validateLevel(level);
        return playerLevels[playerAddress][level].levelWeight;
    }

    function getPlayerChance(address playerAddress, uint8 level)
        external
        view
        returns (uint256 chanceBps)
    {
        _validateLevel(level);
        uint256 total = totalWeightByLevel[level];
        if (total == 0) {
            return 0;
        }
        return (playerLevels[playerAddress][level].levelWeight * BPS) / total;
    }

    function getLevelStats(uint8 level)
        external
        view
        returns (
            uint256 prizePool,
            uint256 totalWeight,
            uint256 activeCells,
            uint256 nextOpenParent,
            uint256 nextCell
        )
    {
        _validateLevel(level);
        return (
            matrixPrizePools[level],
            totalWeightByLevel[level],
            activeCellsByLevel[level],
            nextOpenParentCellId[level],
            nextCellId[level]
        );
    }

    function getLevelStatsUSDC(uint8 level)
        external
        view
        returns (
            uint256 prizePool,
            uint256 totalWeight,
            uint256 activeCells,
            uint256 nextOpenParent,
            uint256 nextCell
        )
    {
        _validateLevel(level);
        return (
            matrixPrizePoolsUsdc[level],
            totalWeightByLevel[level],
            activeCellsByLevel[level],
            nextOpenParentCellId[level],
            nextCellId[level]
        );
    }

    function getPlayerTokenRewards(address playerAddress, uint8 level)
        external
        view
        returns (
            uint256 referralBonus,
            uint256 claimablePrize,
            uint256 pendingPrize
        )
    {
        _validateLevel(level);
        return (
            claimableReferralBonusUsdc[playerAddress],
            claimablePrizeUsdcByLevel[playerAddress][level],
            pendingPrizeUsdcByLevel[playerAddress][level]
        );
    }

    function getLevelMatrixStats(uint8 level)
        external
        view
        returns (uint256 size, uint256 nextOpenParentId)
    {
        _validateLevel(level);
        return (activeCellsByLevel[level], nextOpenParentCellId[level]);
    }

    function getMatrixNode(uint8 level, uint256 cellId)
        external
        view
        returns (MatrixNode memory)
    {
        _validateLevel(level);
        require(cellId > 0 && cellId < nextCellId[level], "Invalid cell");
        return matrixNodes[level][cellId];
    }

    function getPlayerPosition(address playerAddress, uint8 level)
        external
        view
        returns (
            uint256 positionId,
            uint256 parentId,
            uint256 leftChildId,
            uint256 rightChildId,
            uint256 depth,
            bool closed
        )
    {
        _validateLevel(level);
        uint256 cellId = playerLevels[playerAddress][level].cellId;
        if (cellId == 0) {
            return (0, 0, 0, 0, 0, false);
        }

        MatrixNode storage node = matrixNodes[level][cellId];
        return (
            node.cellId,
            node.parentCellId,
            node.leftChildCellId,
            node.rightChildCellId,
            _depthOf(cellId),
            node.closed
        );
    }

    function isLevelActive(address playerAddress, uint8 level)
        external
        view
        returns (bool)
    {
        _validateLevel(level);
        return playerLevels[playerAddress][level].active;
    }

    function isLevelFrozen(address playerAddress, uint8 level)
        external
        view
        returns (bool)
    {
        _validateLevel(level);
        return playerLevels[playerAddress][level].frozen;
    }

    function getNextPrizeCell(uint8 level, uint256 currentCellId)
        external
        pure
        returns (uint256)
    {
        _validateLevelPure(level);
        uint256 candidate = 7;
        while (candidate <= currentCellId) {
            candidate = ((candidate + 1) << 1) - 1;
        }
        return candidate;
    }

    function setLevelPrice(uint8 level, uint256 newPrice) external onlyOwner {
        _validateLevel(level);
        require(newPrice > 0, "Price is required");

        uint256 oldPrice = levelPrices[level];
        levelPrices[level] = newPrice;

        emit LevelPriceChanged(level, oldPrice, newPrice);
    }

    function setLevelPriceUSDC(uint8 level, uint256 newPrice) external onlyOwner {
        _validateLevel(level);
        require(newPrice > 0, "USDC price is required");

        uint256 oldPrice = levelPricesUsdc[level];
        levelPricesUsdc[level] = newPrice;

        emit LevelUsdcPriceChanged(level, oldPrice, newPrice);
    }

    function setUsdcToken(address newToken) external onlyOwner {
        require(newToken != address(0), "USDC token required");
        address oldToken = address(usdcToken);
        usdcToken = IERC20Minimal(newToken);
        emit UsdcTokenChanged(oldToken, newToken);
    }

    function setLevelAvailable(uint8 level, bool available) external onlyOwner {
        _validateLevel(level);
        levelAvailable[level] = available;
        emit LevelAvailabilityChanged(level, available);
    }

    function setWallets(
        address newProjectWallet,
        address newTreasuryWallet,
        address newOperatorWallet
    ) external onlyOwner {
        require(newProjectWallet != address(0), "Project wallet required");
        require(newTreasuryWallet != address(0), "Treasury wallet required");
        require(newOperatorWallet != address(0), "Operator wallet required");

        projectWallet = newProjectWallet;
        treasuryWallet = newTreasuryWallet;
        operatorWallet = newOperatorWallet;

        emit WalletsChanged(projectWallet, treasuryWallet, operatorWallet);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Owner required");
        address oldOwner = owner;
        owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }

    function _registerPlayer(
        Player storage player,
        address playerAddress,
        address inviter
    ) private {
        if (player.exists) {
            return;
        }

        player.exists = true;
        player.wallet = playerAddress;
        player.joinedAt = block.timestamp;

        if (
            inviter != address(0) &&
            inviter != playerAddress &&
            players[inviter].exists
        ) {
            player.inviter = inviter;
            player.secondLine = players[inviter].inviter;
            player.thirdLine = player.secondLine == address(0)
                ? address(0)
                : players[player.secondLine].inviter;
        }
    }

    function _splitPayment(uint8 level, address playerAddress, uint256 amount) private {
        uint256 matrixPrizeAmount = (amount * MATRIX_PRIZE_BPS) / BPS;
        uint256 directReferralAmount = (amount * DIRECT_REF_BPS) / BPS;
        uint256 secondLineAmount = (amount * SECOND_REF_BPS) / BPS;
        uint256 thirdLineAmount = (amount * THIRD_REF_BPS) / BPS;
        uint256 projectFeeAmount = amount -
            matrixPrizeAmount -
            directReferralAmount -
            secondLineAmount -
            thirdLineAmount;

        Player storage player = players[playerAddress];
        matrixPrizePools[level] += matrixPrizeAmount;

        _creditReferral(
            player.inviter,
            playerAddress,
            level,
            directReferralAmount,
            DIRECT_REF_WEIGHT,
            1
        );
        _creditReferral(
            player.secondLine,
            playerAddress,
            level,
            secondLineAmount,
            SECOND_REF_WEIGHT,
            2
        );
        _creditReferral(
            player.thirdLine,
            playerAddress,
            level,
            thirdLineAmount,
            THIRD_REF_WEIGHT,
            3
        );

        projectFeesAccrued += projectFeeAmount;

        emit PaymentSplit(
            playerAddress,
            level,
            matrixPrizeAmount,
            directReferralAmount,
            secondLineAmount,
            thirdLineAmount,
            projectFeeAmount
        );
        emit ProjectFeeAccrued(level, projectFeeAmount, projectFeesAccrued);
    }

    function _splitUsdcPayment(uint8 level, address playerAddress, uint256 amount) private {
        uint256 matrixPrizeAmount = (amount * MATRIX_PRIZE_BPS) / BPS;
        uint256 directReferralAmount = (amount * DIRECT_REF_BPS) / BPS;
        uint256 secondLineAmount = (amount * SECOND_REF_BPS) / BPS;
        uint256 thirdLineAmount = (amount * THIRD_REF_BPS) / BPS;
        uint256 projectFeeAmount = amount -
            matrixPrizeAmount -
            directReferralAmount -
            secondLineAmount -
            thirdLineAmount;

        Player storage player = players[playerAddress];
        matrixPrizePoolsUsdc[level] += matrixPrizeAmount;

        _creditReferralUsdc(
            player.inviter,
            playerAddress,
            level,
            directReferralAmount,
            DIRECT_REF_WEIGHT,
            1
        );
        _creditReferralUsdc(
            player.secondLine,
            playerAddress,
            level,
            secondLineAmount,
            SECOND_REF_WEIGHT,
            2
        );
        _creditReferralUsdc(
            player.thirdLine,
            playerAddress,
            level,
            thirdLineAmount,
            THIRD_REF_WEIGHT,
            3
        );

        projectFeesAccruedUsdc += projectFeeAmount;

        emit TokenPaymentSplit(
            playerAddress,
            level,
            address(usdcToken),
            matrixPrizeAmount,
            directReferralAmount,
            secondLineAmount,
            thirdLineAmount,
            projectFeeAmount
        );
        emit TokenProjectFeeAccrued(
            address(usdcToken),
            level,
            projectFeeAmount,
            projectFeesAccruedUsdc
        );
    }

    function _creditReferral(
        address inviter,
        address invitee,
        uint8 level,
        uint256 amount,
        uint256 weight,
        uint8 line
    ) private {
        if (inviter == address(0) || !players[inviter].exists) {
            matrixPrizePools[level] += amount;
            return;
        }

        players[inviter].claimableReferralBonus += amount;
        _addWeight(inviter, level, weight, 1);

        if (line == 1) {
            emit ReferralBonusAdded(inviter, invitee, level, amount, weight);
        } else if (line == 2) {
            emit SecondLineBonusAdded(inviter, invitee, level, amount, weight);
        } else {
            emit ThirdLineBonusAdded(inviter, invitee, level, amount, weight);
        }
    }

    function _creditReferralUsdc(
        address inviter,
        address invitee,
        uint8 level,
        uint256 amount,
        uint256 weight,
        uint8 line
    ) private {
        if (inviter == address(0) || !players[inviter].exists) {
            matrixPrizePoolsUsdc[level] += amount;
            return;
        }

        claimableReferralBonusUsdc[inviter] += amount;
        _addWeight(inviter, level, weight, 1);

        if (line == 1) {
            emit ReferralBonusAdded(inviter, invitee, level, amount, weight);
        } else if (line == 2) {
            emit SecondLineBonusAdded(inviter, invitee, level, amount, weight);
        } else {
            emit ThirdLineBonusAdded(inviter, invitee, level, amount, weight);
        }
    }

    function _placePlayer(uint8 level, address playerAddress)
        private
        returns (uint256 cellId)
    {
        if (nextCellId[level] == 0) {
            nextCellId[level] = 1;
        }

        cellId = nextCellId[level];
        nextCellId[level] = cellId + 1;

        uint256 parentCellId = cellId == 1 ? 0 : cellId / 2;
        bool prizeCell = _isPrizeCell(cellId);

        MatrixNode storage node = matrixNodes[level][cellId];
        node.cellId = cellId;
        node.player = playerAddress;
        node.level = level;
        node.parentCellId = parentCellId;
        node.prizeCell = prizeCell;

        PlayerLevel storage state = playerLevels[playerAddress][level];
        state.cellId = cellId;
        state.parentCellId = parentCellId;

        activeCellsByLevel[level] += 1;
        levelMatrixSize[level] = activeCellsByLevel[level];

        if (!_levelPlayerSeen[level][playerAddress]) {
            _levelPlayerSeen[level][playerAddress] = true;
            _levelPlayers[level].push(playerAddress);
        }

        if (parentCellId != 0) {
            MatrixNode storage parent = matrixNodes[level][parentCellId];
            if (parent.leftChildCellId == 0) {
                parent.leftChildCellId = cellId;
                playerLevels[parent.player][level].leftChildCellId = cellId;
            } else if (parent.rightChildCellId == 0) {
                parent.rightChildCellId = cellId;
                parent.closed = true;
                playerLevels[parent.player][level].rightChildCellId = cellId;
                _handleRecycle(level, parent.player);
            } else {
                revert("Parent already closed");
            }
        }

        _advanceNextOpenParent(level);
        _awardPrizePosition(playerAddress, level, cellId, prizeCell);

        emit MatrixPlaced(playerAddress, level, cellId, parentCellId);
    }

    function _handleRecycle(uint8 level, address playerAddress) private {
        PlayerLevel storage state = playerLevels[playerAddress][level];
        if (!state.active) {
            return;
        }

        state.cycleCount += 1;
        players[playerAddress].recycleCount += 1;
        players[playerAddress].boxTokens += 1;

        _addWeight(playerAddress, level, RECYCLE_MATRIX_WEIGHT, 3);
        _addWeight(playerAddress, level, BOX_NFT_WEIGHT, 4);

        uint256 newCellId = _placePlayer(level, playerAddress);

        emit Recycled(playerAddress, level, state.cycleCount, newCellId);
        emit BoxTokenGranted(playerAddress, level, 1);

        _freezeAfterRecycle(playerAddress, level);
    }

    function _awardPrizePosition(
        address playerAddress,
        uint8 level,
        uint256 cellId,
        bool prizeCell
    ) private {
        if (!prizeCell) {
            return;
        }

        uint256 reward = (matrixPrizePools[level] * PRIZE_POSITION_BPS) / BPS;
        uint256 usdcReward = (matrixPrizePoolsUsdc[level] * PRIZE_POSITION_BPS) / BPS;

        if (reward > 0) {
            matrixPrizePools[level] -= reward;
            _creditPrize(playerAddress, level, reward);

            emit PrizePositionReached(
                playerAddress,
                level,
                cellId,
                reward,
                playerLevels[playerAddress][level].frozen
            );
        }

        if (usdcReward > 0) {
            matrixPrizePoolsUsdc[level] -= usdcReward;
            _creditPrizeUsdc(playerAddress, level, usdcReward);

            emit TokenPrizePositionReached(
                playerAddress,
                level,
                address(usdcToken),
                cellId,
                usdcReward,
                playerLevels[playerAddress][level].frozen
            );
        }
    }

    function _creditPrize(address playerAddress, uint8 level, uint256 amount) private {
        PlayerLevel storage state = playerLevels[playerAddress][level];
        Player storage player = players[playerAddress];

        if (state.frozen) {
            state.pendingPrize += amount;
            player.pendingPrize += amount;
            return;
        }

        state.claimablePrize += amount;
        player.claimablePrize += amount;
    }

    function _creditPrizeUsdc(address playerAddress, uint8 level, uint256 amount) private {
        PlayerLevel storage state = playerLevels[playerAddress][level];

        if (state.frozen) {
            pendingPrizeUsdcByLevel[playerAddress][level] += amount;
            pendingPrizeUsdc[playerAddress] += amount;
            return;
        }

        claimablePrizeUsdcByLevel[playerAddress][level] += amount;
        claimablePrizeUsdc[playerAddress] += amount;
    }

    function _addWeight(
        address playerAddress,
        uint8 level,
        uint256 amount,
        uint8 weightType
    ) private {
        if (amount == 0) {
            return;
        }

        WeightBreakdown storage breakdown = _levelWeights[playerAddress][level];
        Player storage player = players[playerAddress];
        PlayerLevel storage state = playerLevels[playerAddress][level];

        uint256 accepted = amount;
        if (weightType == 0) {
            accepted = _acceptedWeight(
                breakdown.baseWeight,
                amount,
                MAX_BASE_WEIGHT_PER_LEVEL
            );
            accepted = _acceptedWeight(state.levelWeight, accepted, MAX_TOTAL_WEIGHT_PER_LEVEL);
            breakdown.baseWeight += accepted;
            player.baseWeight += accepted;
        } else if (weightType == 1) {
            accepted = _acceptedWeight(
                breakdown.referralWeight,
                amount,
                MAX_REFERRAL_WEIGHT_PER_LEVEL
            );
            accepted = _acceptedWeight(state.levelWeight, accepted, MAX_TOTAL_WEIGHT_PER_LEVEL);
            breakdown.referralWeight += accepted;
            player.referralWeight += accepted;
        } else if (weightType == 2) {
            accepted = _acceptedWeight(
                breakdown.loyaltyWeight,
                amount,
                MAX_LOYALTY_WEIGHT_PER_LEVEL
            );
            accepted = _acceptedWeight(state.levelWeight, accepted, MAX_TOTAL_WEIGHT_PER_LEVEL);
            breakdown.loyaltyWeight += accepted;
            player.loyaltyWeight += accepted;
        } else if (weightType == 3) {
            accepted = _acceptedWeight(
                breakdown.matrixWeight,
                amount,
                MAX_MATRIX_WEIGHT_PER_LEVEL
            );
            accepted = _acceptedWeight(state.levelWeight, accepted, MAX_TOTAL_WEIGHT_PER_LEVEL);
            breakdown.matrixWeight += accepted;
            player.matrixWeight += accepted;
        } else {
            accepted = _acceptedWeight(
                breakdown.nftWeight,
                amount,
                MAX_NFT_WEIGHT_PER_LEVEL
            );
            accepted = _acceptedWeight(state.levelWeight, accepted, MAX_TOTAL_WEIGHT_PER_LEVEL);
            breakdown.nftWeight += accepted;
            player.nftWeight += accepted;
        }

        if (accepted == 0) {
            return;
        }

        state.levelWeight += accepted;
        player.totalWeight += accepted;
        totalWeightByLevel[level] += accepted;

        emit WeightUpdated(playerAddress, level, state.levelWeight);
    }

    function _acceptedWeight(
        uint256 current,
        uint256 requested,
        uint256 cap
    ) private pure returns (uint256) {
        if (current >= cap) {
            return 0;
        }
        uint256 room = cap - current;
        return requested > room ? room : requested;
    }

    function _weightedWinner(uint8 level, uint256 winningPoint)
        private
        view
        returns (address)
    {
        uint256 cumulative;
        address[] storage levelPlayers = _levelPlayers[level];
        for (uint256 i = 0; i < levelPlayers.length; i++) {
            address candidate = levelPlayers[i];
            cumulative += playerLevels[candidate][level].levelWeight;
            if (winningPoint <= cumulative) {
                return candidate;
            }
        }
        return address(0);
    }

    function _advanceNextOpenParent(uint8 level) private {
        uint256 nextOpen = nextOpenParentCellId[level];
        if (nextOpen == 0) {
            nextOpen = 1;
        }

        while (
            nextOpen < nextCellId[level] &&
            matrixNodes[level][nextOpen].closed
        ) {
            nextOpen++;
        }

        nextOpenParentCellId[level] = nextOpen < nextCellId[level] ? nextOpen : 0;
    }

    function _freezeAfterRecycle(address playerAddress, uint8 level) private {
        PlayerLevel storage state = playerLevels[playerAddress][level];
        if (
            level < LEVEL_COUNT &&
            state.cycleCount >= 2 &&
            !playerLevels[playerAddress][level + 1].active &&
            !state.frozen
        ) {
            state.frozen = true;
            emit LevelFrozen(playerAddress, level);
        }
    }

    function _unfreezeLowerLevels(address playerAddress, uint8 level) private {
        if (level <= 1) {
            return;
        }

        for (uint8 lowerLevel = 1; lowerLevel < level; lowerLevel++) {
            PlayerLevel storage previous = playerLevels[playerAddress][lowerLevel];
            if (previous.frozen) {
                previous.frozen = false;
                if (previous.pendingPrize > 0) {
                    uint256 pending = previous.pendingPrize;
                    previous.pendingPrize = 0;
                    previous.claimablePrize += pending;
                    players[playerAddress].pendingPrize -= pending;
                    players[playerAddress].claimablePrize += pending;
                }
                if (pendingPrizeUsdcByLevel[playerAddress][lowerLevel] > 0) {
                    uint256 pendingUsdc = pendingPrizeUsdcByLevel[playerAddress][lowerLevel];
                    pendingPrizeUsdcByLevel[playerAddress][lowerLevel] = 0;
                    claimablePrizeUsdcByLevel[playerAddress][lowerLevel] += pendingUsdc;
                    pendingPrizeUsdc[playerAddress] -= pendingUsdc;
                    claimablePrizeUsdc[playerAddress] += pendingUsdc;
                }
                emit LevelUnfrozen(playerAddress, lowerLevel);
            }
        }
    }

    function _isPrizeCell(uint256 cellId) private pure returns (bool) {
        return Validation.isPrizeCell(cellId);
    }

    function _depthOf(uint256 cellId) private pure returns (uint256 depth) {
        return Validation.depthOf(cellId);
    }

    function _validateLevel(uint8 level) private pure {
        _validateLevelPure(level);
    }

    function _validateLevelPure(uint8 level) private pure {
        Validation.validateLevel(level);
    }

    function _safeTransfer(address payable receiver, uint256 amount) private {
        if (amount == 0) {
            return;
        }

        (bool ok, ) = receiver.call{value: amount}("");
        require(ok, "Transfer failed");
    }

    function _safeTransferToken(
        IERC20Minimal token,
        address receiver,
        uint256 amount
    ) private {
        if (amount == 0) {
            return;
        }

        require(token.transfer(receiver, amount), "Token transfer failed");
    }
